```java
private void parseStartTag() {
    tq.consume("<");
    String tagName = tq.consumeWord();

    if (tagName.length() == 0) { // If no valid tag name, treat as text
        tq.addFirst("&lt;");
        parseTextNode();
        return;
    }

    Attributes attributes = new Attributes();
    while (!tq.matchesAny("<", "/>", ">") && !tq.isEmpty()) {
        Attribute attribute = parseAttribute();
        if (attribute != null) {
            attributes.put(attribute);
        }
    }

    Tag tag = Tag.valueOf(tagName);
    Element child = new Element(tag, baseUri, attributes);

    boolean isEmptyElement = tag.isEmpty(); // Check if it's an empty element (e.g., <img>)
    if (tq.matchChomp("/>")) { // Handle self-closing tags
        isEmptyElement = true;
    } else {
        tq.matchChomp(">"); // Consume the closing '>'
    }
    addChildToParent(child, isEmptyElement);

    // Handling data only tags (textarea, script)
    if (tag.isData()) {
        String data = tq.chompTo("</" + tagName + ">"); // Correctly chomp to the closing tag
        tq.chompTo(">"); // Consume the '>' after the start tag

        Node dataNode;
        if (tag.equals(titleTag) || tag.equals(textareaTag)) {
            dataNode = TextNode.createFromEncoded(data, baseUri); // Encode data for title/textarea
        } else {
            dataNode = new DataNode(data, baseUri); // Raw data for other tags like script
        }
        child.appendChild(dataNode);   
    }

    // Handle <base href> to update the base URI
    if (child.tagName().equals("base")) {
        String href = child.absUrl("href");
        if (!href.isEmpty()) { // Check that href is not empty
            baseUri = href; // Update base URI
            doc.setBaseUri(href); // Update the document's base URI
        }
    }
}
```

